return [{ json: { systemPrompt, userMessage: userPrompt } }];

// Parse Claude response and map to DB schema
const claudeResponse = $('Call Claude').first().json;
const text = claudeResponse.content[0].text;
const webhookData = $('Webhook').first().json.body;

// Extract JSON from response
let profile;
const codeBlockMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
if (codeBlockMatch) {
  try { profile = JSON.parse(codeBlockMatch[1].trim()); } catch(e) { /* continue */ }
}
if (!profile) {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try { profile = JSON.parse(jsonMatch[0]); } catch(e) { /* continue */ }
  }
}
if (!profile) {
  throw new Error('No valid JSON found in Claude response');
}

// Map Claude output fields to DB column names
const record = {
  tender_id: webhookData.tender_id,
  profile_type: webhookData.profile_type,
  profile_name: profile.profile_name || ('פרופיל ' + webhookData.profile_type),
  company_data: profile.company_data || {},
  generated_projects: profile.projects || [],
  generated_financials: profile.financials || [],
  generated_certifications: profile.certifications || [],
  generated_personnel: profile.personnel || [],
  expected_result: profile.expected_results || {},
  adversarial_tricks: profile.adversarial_tricks || []
};

return [{ json: record }];

// Format the Supabase response for the frontend
const saved = $('Save to DB').first().json;
const record = Array.isArray(saved) ? saved[0] : saved;
return [{ json: record }];
